import React, { useState, useRef, useEffect } from 'react';
import { useReactToPrint } from 'react-to-print';
import { BookingData, RoomType, BookingPlatform } from './types';
import { RESORT_DETAILS, ROOM_TYPES, PLATFORMS } from './constants';
import BookingForm from './components/BookingForm';
import BillPreview from './components/BillPreview';
import { Eye, Download, Printer, PlusCircle, LayoutDashboard } from 'lucide-react';

const App: React.FC = () => {
  const [bookingData, setBookingData] = useState<BookingData>({
    bookingId: '',
    guestName: '',
    bookingDate: new Date().toISOString().split('T')[0],
    checkInDate: '',
    checkOutDate: '',
    reservation: '1 Night, 1 Room',
    roomType: RoomType.SUPERIOR_DELUXE,
    adults: 2,
    children: 0,
    roomRent: 0,
    advanceCollected: 0,
    platform: BookingPlatform.DIRECT,
  });

  const [isPreviewMode, setIsPreviewMode] = useState(false);
  const componentRef = useRef<HTMLDivElement>(null);

  // Auto-generate Booking ID based on some deterministic factors or timestamp
  useEffect(() => {
    if (!bookingData.bookingId) {
      const timestamp = Date.now().toString().slice(-6);
      const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
      setBookingData(prev => ({ ...prev, bookingId: `DV-${timestamp}-${random}` }));
    }
  }, [bookingData.bookingId]);

  const handlePrint = useReactToPrint({
    contentRef: componentRef,
    documentTitle: `DreamyVacations_Bill_${bookingData.guestName.replace(/\s+/g, '_')}`,
  });

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-red-600 selection:text-white pb-12">
      {/* Navigation Header */}
      <header className="sticky top-0 z-50 bg-black/80 backdrop-blur-md border-b border-white/10 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="bg-red-600 p-1.5 rounded">
            <LayoutDashboard className="w-5 h-5 text-white" />
          </div>
          <span className="font-serif text-xl tracking-tight text-red-600 font-bold uppercase">
            DreamyVacations
          </span>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={() => setIsPreviewMode(!isPreviewMode)}
            className="flex items-center gap-2 px-4 py-2 rounded-full bg-white/10 hover:bg-white/20 transition-all text-sm font-medium"
          >
            {isPreviewMode ? <PlusCircle className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            {isPreviewMode ? "Edit Details" : "Preview Bill"}
          </button>

          {isPreviewMode && (
            <>
              <button
                onClick={() => handlePrint()}
                className="flex items-center gap-2 px-4 py-2 rounded-full bg-red-600 hover:bg-red-700 transition-all text-sm font-medium shadow-lg shadow-red-600/20"
              >
                <Printer className="w-4 h-4" />
                Print / PDF
              </button>
            </>
          )}
        </div>
      </header>

      <main className="container mx-auto px-4 mt-8">
        {!isPreviewMode ? (
          <div className="max-w-4xl mx-auto animate-fadeIn">
            <div className="mb-8 text-center">
              <h1 className="text-3xl md:text-4xl font-serif font-bold mb-2">Create New Booking</h1>
              <p className="text-white/60">Fill in the guest details to generate a professional booking confirmation.</p>
            </div>
            <BookingForm 
              data={bookingData} 
              onChange={(newData) => setBookingData(newData)} 
              onSubmit={() => setIsPreviewMode(true)}
            />
          </div>
        ) : (
          <div className="flex flex-col items-center animate-fadeIn">
            <div className="w-full max-w-[210mm] shadow-2xl shadow-white/5 border border-white/5 rounded-lg overflow-hidden bg-white text-black">
               <div ref={componentRef}>
                <BillPreview data={bookingData} />
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

