import React from 'react';
import { BookingData, RoomType, BookingPlatform } from '../types';
import { ROOM_TYPES, PLATFORMS } from '../constants';
import { User, Calendar, Home, CreditCard, ExternalLink } from 'lucide-react';

interface BookingFormProps {
  data: BookingData;
  onChange: (data: BookingData) => void;
  onSubmit: () => void;
}

const BookingForm: React.FC<BookingFormProps> = ({ data, onChange, onSubmit }) => {
  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    const val = type === 'number' ? parseInt(value) || 0 : value;
    onChange({ ...data, [name]: val });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit();
  };

  const inputClasses = "w-full bg-white border border-black/20 focus:border-black focus:ring-1 focus:ring-black rounded-xl px-4 py-3 outline-none transition-all text-black placeholder:text-black/30";

  return (
    <form onSubmit={handleSubmit} className="space-y-8 bg-white border border-black/10 p-6 md:p-10 rounded-2xl shadow-sm">
      {/* Resort Details (Fixed) */}
      <section className="space-y-4">
        <h2 className="text-black font-bold uppercase tracking-widest text-sm flex items-center gap-2">
          <Home className="w-4 h-4" /> Resort Information
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="p-4 bg-zinc-50 rounded-xl border border-black/5">
            <label className="block text-black/60 text-xs mb-1 font-bold">Resort Name</label>
            <p className="font-semibold text-black">Dreamy Vacations</p>
          </div>
          <div className="p-4 bg-zinc-50 rounded-xl border border-black/5">
            <label className="block text-black/60 text-xs mb-1 font-bold">Address</label>
            <p className="text-sm line-clamp-2 text-black font-medium">#51/5, Behind Chikkathur Govt School, Chikkathur Village, Kushalnagar</p>
          </div>
        </div>
      </section>

      {/* Guest & Dates */}
      <section className="space-y-6">
        <h2 className="text-black font-bold uppercase tracking-widest text-sm flex items-center gap-2">
          <User className="w-4 h-4" /> Guest & Booking Details
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1">Guest Name</label>
            <input
              required
              type="text"
              name="guestName"
              value={data.guestName}
              onChange={handleChange}
              placeholder="Full name of guest"
              className={inputClasses}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1">Booking Date</label>
            <input
              required
              type="date"
              name="bookingDate"
              value={data.bookingDate}
              onChange={handleChange}
              className={inputClasses}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1 flex justify-between">
              Check-in Date
              {data.checkInDate && (
                <span className="text-black font-black text-xs uppercase">
                  {new Date(data.checkInDate).toLocaleDateString('en-US', { weekday: 'long' })}
                </span>
              )}
            </label>
            <input
              required
              type="date"
              name="checkInDate"
              value={data.checkInDate}
              onChange={handleChange}
              className={inputClasses}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1 flex justify-between">
              Check-out Date
              {data.checkOutDate && (
                <span className="text-black font-black text-xs uppercase">
                  {new Date(data.checkOutDate).toLocaleDateString('en-US', { weekday: 'long' })}
                </span>
              )}
            </label>
            <input
              required
              type="date"
              name="checkOutDate"
              value={data.checkOutDate}
              onChange={handleChange}
              className={inputClasses}
            />
          </div>
        </div>
      </section>

      {/* Room Selection */}
      <section className="space-y-6">
        <h2 className="text-black font-bold uppercase tracking-widest text-sm flex items-center gap-2">
          <Calendar className="w-4 h-4" /> Room & Occupancy
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1">Room Type</label>
            <select
              name="roomType"
              value={data.roomType}
              onChange={handleChange}
              className={inputClasses}
            >
              {ROOM_TYPES.map(type => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1">Reservation Info</label>
            <input
              type="text"
              name="reservation"
              value={data.reservation}
              onChange={handleChange}
              placeholder="e.g. 1 Night, 1 Room"
              className={inputClasses}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1">Adults</label>
            <input
              type="number"
              name="adults"
              value={data.adults}
              onChange={handleChange}
              min="1"
              className={inputClasses}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1">Children</label>
            <input
              type="number"
              name="children"
              value={data.children}
              onChange={handleChange}
              min="0"
              className={inputClasses}
            />
          </div>
        </div>
      </section>

      {/* Payment Details */}
      <section className="space-y-6">
        <h2 className="text-black font-bold uppercase tracking-widest text-sm flex items-center gap-2">
          <CreditCard className="w-4 h-4" /> Payment Details
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <div className="space-y-1">
            <label className="text-sm font-bold text-black ml-1">Room Rent (₹)</label>
            <input
              required
              type="number"
              name="roomRent"
              value={data.roomRent}
              onChange={handleChange}
              className={inputClasses}
            />
          </div>
          <div className="space-y-1">
