import React, { useState, useEffect } from 'react';
import { BookingData, RoomType, BookingPlatform } from './types';
import { ROOM_TYPES } from './constants';
import BookingForm from './components/BookingForm';
import BillPreview from './components/BillPreview';
import { Eye, Printer, PlusCircle, LayoutDashboard, Loader2 } from 'lucide-react';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const App: React.FC = () => {
  const [bookingData, setBookingData] = useState<BookingData>({
    bookingId: '',
    guestName: '',
    bookingDate: new Date().toISOString().split('T')[0],
    checkInDate: '',
    checkOutDate: '',
    numRooms: 1,
    numNights: 0,
    reservation: '',
    roomType: RoomType.SUPERIOR_DELUXE,
    adults: 2,
    children: 0,
    roomRent: 0,
    advanceCollected: 0,
    platform: BookingPlatform.DIRECT,
    logo: '',
  });

  const [isPreviewMode, setIsPreviewMode] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
    if (!bookingData.bookingId) {
      const timestamp = Date.now().toString().slice(-6);
      const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
      setBookingData(prev => ({ ...prev, bookingId: `DV-${timestamp}-${random}` }));
    }
  }, [bookingData.bookingId]);

  useEffect(() => {
    if (bookingData.checkInDate && bookingData.checkOutDate) {
      const start = new Date(bookingData.checkInDate);
      const end = new Date(bookingData.checkOutDate);

      start.setHours(0, 0, 0, 0);
      end.setHours(0, 0, 0, 0);

      const diffTime = end.getTime() - start.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays > 0) {
        const rooms = bookingData.numRooms || 1;
        const reservationStr = `${diffDays} Night${diffDays > 1 ? 's' : ''}, ${rooms} Room${rooms > 1 ? 's' : ''}`;

        if (bookingData.numNights !== diffDays || bookingData.reservation !== reservationStr) {
          setBookingData(prev => ({
            ...prev,
            numNights: diffDays,
            reservation: reservationStr
          }));
        }
      } else {
        if (bookingData.numNights !== 0 || bookingData.reservation !== '') {
          setBookingData(prev => ({
            ...prev,
            numNights: 0,
            reservation: ''
          }));
        }
      }
    }
  }, [bookingData.checkInDate, bookingData.checkOutDate, bookingData.numRooms, bookingData.numNights, bookingData.reservation]);

  const handleGeneratePdf = async () => {
    const container = document.querySelector('.bill-container');
    if (!container) return;

    setIsGenerating(true);
    try {
      const pages = container.querySelectorAll('.page');
      const pdf = new jsPDF({
        orientation: 'p',
        unit: 'mm',
        format: 'a4',
        compress: true
      });

      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      for (let i = 0; i < pages.length; i++) {
        const page = pages[i] as HTMLElement;
        const logoTarget = page.querySelector('[data-pdf-logo="true"]') as HTMLElement;

        const canvas = await html2canvas(page, {
          scale: 2,
          useCORS: true,
          allowTaint: true,
          logging: false,
          backgroundColor: '#FFFFFF',
          imageTimeout: 15000
        });

        const imgData = canvas.toDataURL('image/jpeg', 0.90);

        if (i > 0) pdf.addPage();
        pdf.addImage(imgData, 'JPEG', 0, 0, pdfWidth, pdfHeight, undefined, 'FAST');

        // Re-inject the high-quality logo if it exists
        if (logoTarget && bookingData.logo) {
          try {
            const rect = logoTarget.getBoundingClientRect();
            const pageRect = page.getBoundingClientRect();
            const scale = pdfWidth / pageRect.width;

            const x = (rect.left - pageRect.left) * scale;
            const y = (rect.top - pageRect.top) * scale;
            const w = rect.width * scale;
            const h = rect.height * scale;

            // Clear the area first
            pdf.setFillColor(255, 255, 255);
            pdf.rect(x, y, w, h, 'F');

            // Add the high-res base64 image
            pdf.addImage(
              bookingData.logo, 
              'PNG', 
              x, 
              y, 
              w, 
              h, 
              undefined, 
              'MEDIUM'
            );
          } catch (logoError) {
            console.warn("High-res logo injection failed, falling back to canvas version", logoError);
          }
        }
      }

      pdf.save(`DreamyVacations_${bookingData.bookingId}.pdf`);
    } catch (error) {
      console.error('CRITICAL: PDF generation crashed:', error);
      alert('We encountered an error generating the PDF. Please try again.');
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-white text-black font-sans pb-12">
      <header className="no-print sticky top-0 z-50 bg-white/90 backdrop-blur-md border-b border-black/10 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="bg-white border border-black p-1.5 rounded">
            <LayoutDashboard className="w-5 h-5 text-black" />
          </div>
          <span className="font-serif text-xl tracking-tight text-black font-bold uppercase">
            DreamyVacations
          </span>
        </div>

        <div className="flex items-center gap-3">
          <button
            disabled={isGenerating}
            onClick={() => setIsPreviewMode(!isPreviewMode)}
            className="flex items-center gap-2 px-4 py-2 rounded-full bg-white border border-black hover:bg-black hover:text-white transition-all text-sm font-medium disabled:opacity-50"
          >
            {isPreviewMode ? <PlusCircle className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            {isPreviewMode ? "Edit Details" : "Preview Bill"}
          </button>

          {isPreviewMode && (
            <button
              disabled={isGenerating}
              onClick={handleGeneratePdf}
              className="flex items-center gap-2 px-4 py-2 rounded-full bg-white border border-black text-black hover:bg-black hover:text-white transition-all text-sm font-medium shadow-sm disabled:bg-zinc-100"
            >
              {isGenerating ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Printer className="w-4 h-4" />
              )}
              {isGenerating ? "Generating..." : "Download PDF"}
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-4 mt-8">
        {!isPreviewMode ? (
          <div className="max-w-4xl mx-auto animate-fadeIn">
            <div className="mb-8 text-center">
              <h1 className="text-3xl md:text-4xl font-serif font-bold mb-2 text-black">Create New Booking</h1>
              <p className="text-black/60">Fill in the guest details to generate a professional booking confirmation.</p>
            </div>
            <BookingForm 
              data={bookingData} 
              onChange={(newData) => setBookingData(newData)} 
              onSubmit={() => setIsPreviewMode(true)}
            />
          </div>
        ) : (
          <div className="flex flex-col items-center animate-fadeIn">
            <div className="bill-wrapper w-full max-w-[210mm] shadow-xl border border-black/5 rounded-lg overflow-hidden bg-white text-black">
              <BillPreview data={bookingData} />
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

