                    >
                      <Plus className="w-5 h-5" />
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2 mt-2">
                    {data.snacksCustomItems.map((item, idx) => (
                      <span key={idx} className="bg-white/10 border border-white/20 text-white text-[11px] px-3 py-1 rounded-full flex items-center gap-2">
                        {item}
                        <button type="button" onClick={() => removeCustomItem('snacksCustomItems', idx)} className="hover:text-red-400 transition-colors">
                          <X className="w-3 h-3" />
                        </button>
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </section>

      {/* Payment Details */}
      <section className="space-y-6">
        <h2 className={sectionHeaderClasses}>
          <CreditCard className="w-4 h-4" color={iconColor} /> Payment Details
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <div className="space-y-1">
            <label className={labelClasses}>Room Rent (₹)</label>
            <input required type="number" name="roomRent" value={data.roomRent} onChange={handleChange} className={inputClasses} />
          </div>
          <div className="space-y-1">
            <label className={labelClasses}>Advance Collected (₹)</label>
            <input required type="number" name="advanceCollected" value={data.advanceCollected} onChange={handleChange} className={inputClasses} />
          </div>
          <div className="space-y-1">
            <label className={labelClasses}>Booking Platform</label>
            <select name="platform" value={data.platform} onChange={handleChange} className={inputClasses}>
              {PLATFORMS.map(p => <option key={p} value={p}>{p}</option>)}
            </select>
          </div>
        </div>
        <div className="p-5 rounded-xl border-2 bg-[#111111] border-white text-white shadow-sm flex justify-between items-center">
          <span className="text-xs font-bold uppercase tracking-widest text-[#E0E0E0]">Balance:</span>
          <span className="text-2xl font-black">{data.roomRent - data.advanceCollected === 0 ? 'FULL PAYMENT DONE' : `₹ ${data.roomRent - data.advanceCollected}`}</span>
        </div>
      </section>

      <div className="pt-8">
        <button
          type="submit"
          className="w-full md:w-auto px-12 py-4 bg-white text-black font-black rounded-xl transition-all shadow-md flex items-center justify-center gap-3 hover:bg-[#E0E0E0] hover:scale-[1.02] active:scale-100"
        >
          Generate Bill Preview <ExternalLink className="w-5 h-5" />
        </button>
      </div>
    </form>
  );
};

