import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { BookingData, RoomType, BookingPlatform } from './types';
import { ROOM_TYPES } from './constants';
import BookingForm from './components/BookingForm';
import BillPreview from './components/BillPreview';
import { Eye, Printer, PlusCircle, LayoutDashboard, Loader2 } from 'lucide-react';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const App: React.FC = () => {
  const [bookingData, setBookingData] = useState<BookingData>({
    bookingId: '',
    guestName: '',
    bookingDate: new Date().toISOString().split('T')[0],
    checkInDate: '',
    checkOutDate: '',
    numRooms: 1,
    numNights: 0,
    reservation: '',
    roomType: '', 
    adults: 2,
    children: 0,
    roomRent: 0,
    advanceCollected: 0,
    platform: BookingPlatform.DIRECT,
    logo: '',
    includeBreakfast: false,
    breakfastItems: [],
    breakfastCustomItems: [],
    includeDinner: false,
    dinnerItems: [],
    dinnerCustomItems: [],
    includeSnacks: false,
    snacksItems: [],
    snacksCustomItems: [],
  });

  const [isPreviewMode, setIsPreviewMode] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
    if (!bookingData.bookingId) {
      const timestamp = Date.now().toString().slice(-6);
      const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
      setBookingData(prev => ({ ...prev, bookingId: `DV-${timestamp}-${random}` }));
    }
  }, [bookingData.bookingId]);

  // DERIVED STATE EFFECT: numNights and reservation string
  // CRITICAL FIX: Removed numNights and reservation from dependencies to prevent infinite render loops.
  useEffect(() => {
    if (bookingData.checkInDate && bookingData.checkOutDate) {
      const start = new Date(bookingData.checkInDate);
      const end = new Date(bookingData.checkOutDate);

      start.setHours(0, 0, 0, 0);
      end.setHours(0, 0, 0, 0);

      const diffTime = end.getTime() - start.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays > 0) {
        const rooms = bookingData.numRooms || 1;
        const reservationStr = `${diffDays} Night${diffDays > 1 ? 's' : ''}, ${rooms} Room${rooms > 1 ? 's' : ''}`;

        setBookingData(prev => {
          // Strict equality check to prevent unnecessary updates
          if (prev.numNights === diffDays && prev.reservation === reservationStr) {
            return prev;
          }
          return {
            ...prev,
            numNights: diffDays,
            reservation: reservationStr
          };
        });
      } else {
        setBookingData(prev => {
          if (prev.numNights === 0 && prev.reservation === '') {
            return prev;
          }
          return {
            ...prev,
            numNights: 0,
            reservation: ''
          };
        });
      }
    }
  }, [bookingData.checkInDate, bookingData.checkOutDate, bookingData.numRooms]);

  const handleGeneratePdf = async () => {
    setIsGenerating(true);

    const hiddenHost = document.createElement('div');
    Object.assign(hiddenHost.style, {
      position: 'absolute',
      left: '-9999px',
      top: '0',
      width: '210mm',
      backgroundColor: '#FFFFFF',
      zIndex: '-1000'
    });
    document.body.appendChild(hiddenHost);

    const root = createRoot(hiddenHost);

    await new Promise<void>((resolve) => {
      root.render(<BillPreview data={bookingData} isPdf={true} />);
      setTimeout(resolve, 600);
    });

    try {
      const pdf = new jsPDF({
        orientation: 'p',
        unit: 'mm',
        format: 'a4',
        compress: true
      });

      const pdfWidth = 210; 
      const pdfHeight = 297; 

      const billPages = hiddenHost.querySelectorAll('.page');

      for (let i = 0; i < billPages.length; i++) {
        const page = billPages[i] as HTMLElement;

        const canvas = await html2canvas(page, {
          scale: 2,
          useCORS: true,
          allowTaint: true,
          logging: false,
          backgroundColor: '#FFFFFF',
          width: 794,
          windowWidth: 794, 
          imageTimeout: 15000
        });

        const imgData = canvas.toDataURL('image/jpeg', 0.90);

        if (i > 0) pdf.addPage();
        pdf.addImage(imgData, 'JPEG', 0, 0, pdfWidth, pdfHeight, undefined, 'FAST');

        const logoTarget = page.querySelector('[data-pdf-logo="true"]') as HTMLElement;
        if (logoTarget && bookingData.logo) {
          try {
            const rect = logoTarget.getBoundingClientRect();
            const pageRect = page.getBoundingClientRect();

            const scaleFactor = pdfWidth / pageRect.width;

            const x = (rect.left - pageRect.left) * scaleFactor;
            const y = (rect.top - pageRect.top) * scaleFactor;
            const w = rect.width * scaleFactor;
            const h = rect.height * scaleFactor;

            pdf.setFillColor(255, 255, 255);
            pdf.rect(x, y, w, h, 'F');

            pdf.addImage(
              bookingData.logo, 
              'PNG', 
              x, 
              y, 
              w, 
              h, 
              undefined, 
              'MEDIUM'
            );
          } catch (logoError) {
            console.warn("Logo re-injection failed", logoError);
          }
        }
      }

      pdf.save(`DreamyVacations_${bookingData.bookingId}.pdf`);
    } catch (error) {
      console.error('CRITICAL: PDF generation crashed:', error);
      alert('We encountered an error generating the PDF. Please try again.');
    } finally {
      root.unmount();
      document.body.removeChild(hiddenHost);
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-black text-white font-sans pb-12 overflow-x-hidden">
      <header className="no-print sticky top-0 z-50 bg-black/90 backdrop-blur-md border-b border-[#2A2A2A] px-4 sm:px-6 py-4 flex flex-wrap items-center justify-between gap-y-4 w-full max-w-[100vw] overflow-hidden">
        <div className="flex items-center gap-2 shrink-0">
          <div className="bg-black border border-white p-1.5 rounded">
            <LayoutDashboard className="w-5 h-5 text-white" />
          </div>
          <span className="font-serif text-lg sm:text-xl tracking-tight text-white font-bold uppercase">
            DreamyVacations
          </span>
        </div>

        <div className="flex flex-wrap items-center gap-2 sm:gap-3">
          <button
            disabled={isGenerating}
            onClick={() => setIsPreviewMode(!isPreviewMode)}
            className="flex items-center gap-2 px-3 sm:px-4 py-2 rounded-full bg-transparent border border-white text-white hover:bg-white hover:text-black transition-all text-xs sm:text-sm font-medium disabled:opacity-50 whitespace-nowrap"
          >
            {isPreviewMode ? <PlusCircle className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            {isPreviewMode ? "Edit Details" : "Preview Bill"}
          </button>

          {isPreviewMode && (
            <button
              disabled={isGenerating}
              onClick={handleGeneratePdf}
              className="flex items-center gap-2 px-3 sm:px-4 py-2 rounded-full bg-white border border-white text-black hover:bg-zinc-200 transition-all text-xs sm:text-sm font-medium shadow-sm disabled:opacity-50 whitespace-nowrap"
            >
              {isGenerating ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Printer className="w-4 h-4" />
              )}
              {isGenerating ? "Generating..." : "Download PDF"}
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-4 mt-8">
        {!isPreviewMode ? (
          <div className="max-w-4xl mx-auto animate-fadeIn">
            <div className="mb-8 text-center">
              <h1 className="text-3xl md:text-4xl font-serif font-bold mb-2 text-white">Create New Booking</h1>
              <p className="text-[#E0E0E0]">Fill in the guest details to generate a professional booking confirmation.</p>
            </div>
            <BookingForm 
              data={bookingData} 
              onChange={(newData) => setBookingData(newData)} 
              onSubmit={() => setIsPreviewMode(true)}
            />
          </div>
        ) : (
          <div className="flex flex-col items-center animate-fadeIn">
            <div className="bill-wrapper w-full max-w-4xl shadow-xl border border-[#2A2A2A] rounded-lg overflow-hidden bg-white text-black">
              <BillPreview data={bookingData} isPdf={false} />
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { BookingData, RoomType, BookingPlatform } from '../types';
import { ROOM_TYPES, PLATFORMS, BREAKFAST_MENU, DINNER_MENU, EVENING_SNACKS_MENU } from '../constants';
import { User, Calendar, Home, CreditCard, ExternalLink, AlertCircle, Clock, Upload, Trash2, Utensils, Plus, X } from 'lucide-react';

interface BookingFormProps {
  data: BookingData;
  onChange: (data: BookingData) => void;
  onSubmit: () => void;
}

const BookingForm: React.FC<BookingFormProps> = ({ data, onChange, onSubmit }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [customBreakfast, setCustomBreakfast] = useState('');
  const [customDinner, setCustomDinner] = useState('');
  const [customSnacks, setCustomSnacks] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    const val = type === 'number' ? parseInt(value) || 0 : value;
    onChange({ ...data, [name]: val });
  };

  const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, checked } = e.target;
    onChange({ ...data, [name]: checked });
  };

  const toggleItem = (listName: 'breakfastItems' | 'dinnerItems' | 'snacksItems', item: string) => {
    const current = data[listName];
    if (current.includes(item)) {
      onChange({ ...data, [listName]: current.filter(i => i !== item) });
    } else {
      onChange({ ...data, [listName]: [...current, item] });
    }
  };

  const addCustomItem = (listName: 'breakfastCustomItems' | 'dinnerCustomItems' | 'snacksCustomItems', value: string, setter: (v: string) => void) => {
    if (!value.trim()) return;
    onChange({ ...data, [listName]: [...data[listName], value.trim()] });
    setter('');
  };

  const removeCustomItem = (listName: 'breakfastCustomItems' | 'dinnerCustomItems' | 'snacksCustomItems', index: number) => {
    const newList = [...data[listName]];
    newList.splice(index, 1);
    onChange({ ...data, [listName]: newList });
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert("Logo file size must be less than 2MB.");
        return;
      }
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        onChange({ ...data, logo: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLogo = () => {
    onChange({ ...data, logo: '' });
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!data.roomType) {
      alert("Please select a Room Type (Room or Cottage).");
      return;
    }
    if (data.numNights <= 0 && data.checkInDate && data.checkOutDate) {
      alert("Check-out date must be after Check-in date.");
      return;
    }
    onSubmit();
  };

  const inputClasses = "w-full bg-[#111111] border border-[#2A2A2A] focus:border-white focus:ring-1 focus:ring-white rounded-xl px-4 py-3 outline-none transition-all text-white placeholder:text-[#AAAAAA] input-shadow";
  const disabledClasses = "w-full bg-[#111111] border border-[#2A2A2A] rounded-xl px-4 py-3 text-[#E0E0E0]/50 cursor-not-allowed font-bold";
  const labelClasses = "text-sm font-bold text-[#E0E0E0] ml-1 block mb-1";
  const sectionHeaderClasses = "text-white font-bold uppercase tracking-wider text-sm flex items-center gap-2 border-b border-[#2A2A2A] pb-2 mb-6";
  const iconColor = "#FFFFFF";

  const isInvalidDateRange = data.checkInDate && data.checkOutDate && data.numNights <= 0;

  return (
    <form onSubmit={handleSubmit} className="space-y-12 bg-[#000000] border border-[#2A2A2A] p-6 md:p-10 rounded-2xl shadow-sm">
      {/* Logo Upload */}
      <section className="space-y-4">
        <h2 className={sectionHeaderClasses}>
          <Upload className="w-4 h-4" color={iconColor} /> Upload Resort Logo
        </h2>
        <div className="flex flex-col md:flex-row items-center gap-6 p-6 bg-[#0F0F0F] border border-dashed border-[#2A2A2A] rounded-2xl">
          <div className="w-24 h-24 bg-[#111111] border border-[#2A2A2A] rounded-xl flex items-center justify-center overflow-hidden shrink-0 shadow-sm">
            {data.logo ? (
              <img src={data.logo} alt="Resort Logo" className="w-full h-full object-contain" />
            ) : (
              <Home className="w-8 h-8 text-[#2A2A2A]" />
            )}
          </div>
          <div className="flex-1 space-y-2">
            <p className="text-xs text-[#E0E0E0] font-medium">Add your resort logo to appear on all pages of the bill. (PNG/JPG, Max 2MB)</p>
            <div className="flex gap-2">
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleLogoUpload}
                className="hidden"
              />
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="px-4 py-2 bg-white text-black text-xs font-bold rounded-lg hover:bg-[#E0E0E0] transition-colors shadow-sm"
              >
                {data.logo ? "Change Logo" : "Choose Logo"}
              </button>
              {data.logo && (
                <button
                  type="button"
                  onClick={removeLogo}
                  className="px-4 py-2 border border-[#2A2A2A] text-white text-xs font-bold rounded-lg hover:bg-white hover:text-black transition-colors flex items-center gap-1 shadow-sm"
                >
                  <Trash2 className="w-3 h-3" /> Remove
                </button>
              )}
            </div>
          </div>
        </div>
      </section>

      {/* Resort Information */}
      <section className="space-y-4">
        <h2 className={sectionHeaderClasses}>
          <Home className="w-4 h-4" color={iconColor} /> Resort Information
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="p-4 bg-[#0F0F0F] rounded-xl border border-[#2A2A2A] shadow-sm">
            <label className="block text-[#E0E0E0] text-[10px] uppercase tracking-wider mb-1 font-bold">Resort Name</label>
            <p className="font-semibold text-white">Dreamy Vacations</p>
          </div>
          <div className="p-4 bg-[#0F0F0F] rounded-xl border border-[#2A2A2A] shadow-sm">
            <label className="block text-[#E0E0E0] text-[10px] uppercase tracking-wider mb-1 font-bold">Address</label>
            <p className="text-sm line-clamp-2 text-white font-medium">#51/5, Behind Chikkathur Govt School, Chikkathur Village, Kushalnagar, Kudumangalore, Coorg, Karnataka 571232</p>
          </div>
        </div>
      </section>

      {/* Guest & Dates */}
      <section className="space-y-6">
        <h2 className={sectionHeaderClasses}>
          <User className="w-4 h-4" color={iconColor} /> Guest & Booking Details
